mbr.copysrc:
     /* =================================================================== */
     /*                                                                     */
     /*  Documentation:                                                     */
     /*                                                                     */
     /*  Utility . . . : LSTJOB                                             */
     /*  Object  . . . : A_INSTALL  (PGM)                                   */
     /*  Source member : A_INSTALL                                          */
     /*  Source type . : CLLE                                               */
     /*  Description   : LSTJOB - Installer                                 */
     /*  Author  . . . : Thomas Raddatz   <thomas.raddatz@tools400.de>      */
     /*                                                                     */
     /* =================================================================== */
     /*                                                                     */
     /*  This software is free software, you can redistribute it and/or     */
     /*  modify it under the terms of the GNU General Public License (GPL)  */
     /*  as published by the Free Software Foundation.                      */
     /*                                                                     */
     /*  See GNU General Public License for details.                        */
     /*          http://www.opensource.org                                  */
     /*          http://www.opensource.org/licenses/gpl-license.html        */
     /*                                                                     */
     /* =================================================================== */
     /*  History:                                                           */
     /*                                                                     */
     /*  Datum       Name          Änderung                                 */
     /*  ----------  ------------  ---------------------------------------  */
     /*                                                                     */
     /* =================================================================== */
     /*   >>PRE-COMPILER<<                                                  */
     /*     >>CRTCMD<<    CRTBNDCL  PGM(QTEMP/&OB) +                        */
     /*                             SRCFILE(&SL/&SF) SRCMBR(&SM);           */
     /*     >>IMPORTANT<<                                                   */
     /*       >>PARM<<    OPTION(*EVENTF);                                  */
     /*     >>END-IMPORTANT<<                                               */
     /*     >>EXECUTE<<                                                     */
     /*     >>CMD<<       CALL   PGM(QTEMP/A_INSTALL) +                     */
     /*                          PARM('*CURRENT' '&SF' '&LI' 'NO');         */
     /*     >>CMD<<       DLTPGM PGM(QTEMP/A_INSTALL);                      */
     /*   >>END-PRE-COMPILER<<                                              */
     /* =================================================================== */
             PGM        PARM(&TGTRLS &SRCFILE &TOLIB &CRTTSTPGM)

             DCL        VAR(&TGTRLS   ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&SRCFILE  ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&TOLIB    ) TYPE(*CHAR) LEN(10)
             DCL        VAR(&CRTTSTPGM) TYPE(*CHAR) LEN(10)

             DCL        VAR(&SRCLIB   ) TYPE(*CHAR) LEN(10)

             CHGVAR     VAR(&SRCLIB) VALUE(&TOLIB   )

     /* -------------------------------- */
     /*  Delete old objects              */
     /* -------------------------------- */
             DLTMOD     MODULE(&TOLIB/LSTJOBR1)
             MONMSG     MSGID(CPF2105)

             DLTSRVPGM  SRVPGM(&TOLIB/LSTJOB)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/LSTJOB_T1)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/LSTJOB_T1)
             MONMSG     MSGID(CPF2105)

             DLTMOD     MODULE(&TOLIB/LSTJOB_T2)
             MONMSG     MSGID(CPF2105)

             DLTPGM     PGM(&TOLIB/LSTJOB_T2)
             MONMSG     MSGID(CPF2105)

     /* -------------------------------- */
     /*  Create modules                  */
     /* -------------------------------- */
             CRTRPGMOD  MODULE(&TOLIB/LSTJOBR1) +
                          SRCFILE(&SRCLIB/&SRCFILE) SRCMBR(*MODULE) +
                          DBGVIEW(*LIST) TRUNCNBR(*NO) +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(LSTJOBR1 ) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create service programs         */
     /* -------------------------------- */
             CRTSRVPGM  SRVPGM(&TOLIB/LSTJOB) +
                          MODULE(&TOLIB/LSTJOBR1) +
                          EXPORT(*SRCFILE) +
                          SRCFILE(&SRCLIB/&SRCFILE) +
                          SRCMBR(LSTJOB) +
                          ACTGRP(*CALLER) +
                          DETAIL(*BASIC) +
                          BNDSRVPGM(&TOLIB/BASICS1) +
                          TEXT('List Jobs API') +
                          TGTRLS(&TGTRLS)
             DLTSPLF    FILE(LSTJOB) JOB(*) SPLNBR(*LAST)
             MONMSG     MSGID(CPF0000)

     /* -------------------------------- */
     /*  Create test programs            */
     /* -------------------------------- */
             IF         COND(&CRTTSTPGM *EQ 'YES') THEN(DO)
                CRTRPGMOD  MODULE(&TOLIB/LSTJOB_T1) +
                             SRCFILE(&SRCLIB/&SRCFILE) +
                             SRCMBR(*MODULE) +
                             DBGVIEW(*LIST) +
                             TRUNCNBR(*NO) +
                             TGTRLS(&TGTRLS)
                DLTSPLF    FILE(LSTJOB_T1) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                CRTPGM     PGM(&TOLIB/LSTJOB_T1) +
                             MODULE(*PGM) +
                             BNDSRVPGM(&TOLIB/LSTJOB) +
                             ACTGRP(*NEW) +
                             DETAIL(*BASIC) +
                             TGTRLS(&TGTRLS)
                DLTSPLF    FILE(LSTJOB_T1) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                DLTMOD    MODULE(&TOLIB/LSTJOB_T1)

                CRTRPGMOD  MODULE(&TOLIB/LSTJOB_T2) +
                             SRCFILE(&SRCLIB/&SRCFILE) +
                             SRCMBR(*MODULE) +
                             DBGVIEW(*LIST) +
                             TRUNCNBR(*NO) +
                             TGTRLS(&TGTRLS)
                DLTSPLF    FILE(LSTJOB_T2) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                CRTPGM     PGM(&TOLIB/LSTJOB_T2) +
                             MODULE(*PGM) +
                             BNDSRVPGM(&TOLIB/LSTJOB) +
                             ACTGRP(*NEW) +
                             DETAIL(*BASIC) +
                             TGTRLS(&TGTRLS)
                DLTSPLF    FILE(LSTJOB_T2) JOB(*) SPLNBR(*LAST)
                MONMSG     MSGID(CPF0000)

                DLTMOD    MODULE(&TOLIB/LSTJOB_T2)
             ENDDO

     /* -------------------------------- */
     /*  Delete obsolete objects         */
     /* -------------------------------- */
             DLTMOD     MODULE(&TOLIB/LSTJOBR1)

             ENDPGM

     /* ====================================================================== */
     /* >>PRE-COMPILER<<                                                       */
     /*   >>CRTCMD<< CRTSRVPGM    SRVPGM(&LI/&OB);                             */
     /*   >>COMPILE<<                                                          */
     /*     >>PARM<< MODULE(&LI/LSTJOBR1  +                                    */
     /*                                );                                      */
     /*     >>PARM<< EXPORT(*SRCFILE);                                         */
     /*     >>PARM<<   SRCFILE(&SL/&SF);                                       */
     /*     >>PARM<<   SRCMBR(&SM);                                            */
     /*     >>PARM<< ACTGRP(*CALLER);                                          */
     /*     >>PARM<< BNDSRVPGM(*LIBL/BASICS1);                                 */
     /*     >>PARM<< ALWUPD(*YES);                                             */
     /*     >>PARM<< ALWLIBUPD(*YES);                                          */
     /*     >>PARM<< TEXT('Tools/400: List Jobs');                             */
     /*     >>PARM<< TGTRLS(V6R1M0);                                           */
     /*     >>PARM<< DETAIL(*BASIC);                                           */
     /*   >>END-COMPILE<<                                                      */
     /*   >>LINK<<                                                             */
     /*   >>END-LINK<<                                                         */
     /*   >>EXECUTE<<                                                          */
     /* >>END-PRE-COMPILER<<                                                   */
     /* ====================================================================== */

STRPGMEXP PGMLVL(*CURRENT) SIGNATURE('Version 2.1')

  EXPORT SYMBOL('LSTJOBR1_f_cloJobLst')
  EXPORT SYMBOL('LSTJOBR1_f_getFirstJob')
  EXPORT SYMBOL('LSTJOBR1_f_getNextJob')
  EXPORT SYMBOL('LSTJOBR1_f_getNumJobAvl')
  EXPORT SYMBOL('LSTJOBR1_f_opnJobLst')
  EXPORT SYMBOL('LSTJOBR1_f_rtvJobA')

ENDPGMEXP

STRPGMEXP PGMLVL(*PRV    ) SIGNATURE(x'FC7B1E63785F206B146B2671D5DDA7EE')

  EXPORT SYMBOL('LSTJOBR1_f_cloJobLst')
  EXPORT SYMBOL('LSTJOBR1_f_getFirstJob')
  EXPORT SYMBOL('LSTJOBR1_f_getNextJob')
  EXPORT SYMBOL('LSTJOBR1_f_getNumJobAvl')
  EXPORT SYMBOL('LSTJOBR1_f_opnJobLst')
  EXPORT SYMBOL('LSTJOBR1_f_rtvJobA')

ENDPGMEXP

*=====================================================================* * Author : Thomas Raddatz * * Date : 05.04.2016 * * E-mail : Thomas.Raddatz@Tools400.de * * Homepage: www.tools400.de * *=====================================================================* * * * This software is free software, you can redistribute it and/or * * modify it under the terms of the GNU General Public License (GPL) * * as published by the Free Software Foundation. * * * * See GNU General Public License for details. * * http://www.opensource.org * * http://www.opensource.org/licenses/gpl-license.html * * * *=====================================================================* * History: * * * * Datum Name Änderung * * ---------- ------------ --------------------------------------- * * * *=====================================================================* * >>PRE-COMPILER<< * * >>CRTCMD<< CRTRPGMOD MODULE(&LI/&OB) + * * SRCFILE(&SL/&SF) + * * SRCMBR(&SM); * * >>COMPILE<< * * >>PARM<< TRUNCNBR(*NO); * * >>PARM<< DBGVIEW(*LIST); * * >>PARM<< TGTRLS(V6R1M0); * * >>END-COMPILE<< * * >>EXECUTE<< * * >>CMD<< CRTPGM PGM(&LI/&OB) + * * MODULE(*PGM) + * * BNDSRVPGM(&LI/LSTJOB) + * * ACTGRP(*NEW) + * * DETAIL(*BASIC); * * >>END-PRE-COMPILER<< * *=====================================================================* H EXTBININT(*YES) H DATFMT(*ISO) TIMFMT(*ISO) DEBUG(*YES) *=====================================================================* * /COPY QLSTJOB,PLSTJOB List Jobs Service Program /COPY QLSTJOB,QUSLJOB List Job (QUSLJOB) API /COPY QLSTJOB,FDJOBI0200 QUSRJOBI API - JOBI0200 * * *ENTRY Parameterliste D LSTJOB_T2... D PR extpgm('LSTJOB_T2') D gi_job 10A const * * Prototypen für interne Funktionen D p_main... D PR D i_job 10A const * ******************************************************************** * Hauptsteuerleiste des RPG ******************************************************************** D LSTJOB_T2... D PI D gi_job 10A const *------------------------------------------------------------------- /free
p_main(gi_job); *inlr = *on;
/end-free
*==================================================================* * Main Prozedur * (so hat man auch in der "Hauptsteuerleiste" lokale Variablen) *==================================================================* P p_main... P B export D PI D i_job 10A const * * Lokale Arbeitsfelder D hasJob S N D hJobs S like(lstJob_handle_t) inz D jobl0100 DS likeds(jobl0100_t) inz D jobi0200 DS likeds(jobi0200_t) inz D msg DS likeds(msg_t) inz *------------------------------------------------------------------- /free
// Öffnen Liste der Jobs hasJob = f_opnJobLst(i_job: '*ALL': '*ALL': '*ACTIVE' : cLSTJOB_ORDERBY_NONE: hJobs);
// Lesen 1. Job der Liste hasJob = f_getFirstJob(hJobs: jobl0100); dow hasJob;
// Abrufen Jobinformationen jobi0200 = f_rtvJobA(jobl0100.intJobID: 'JOBI0200': msg); if (msg.ID <> cMSG_ID_OK); // Fehler beim Abrufen der Jobinformationen else; if (jobi0200.actJobSts = 'DSC'); // Job Status = DISCONNECTED endif; endif;
hasJob = f_getNextJob(hJobs: jobl0100); enddo;
f_cloJobLst(hJobs);
/end-free P E

*=====================================================================* * Author : Thomas Raddatz * * Date : 04.12.2003 * * E-mail : Thomas.Raddatz@Tools400.de * * Homepage: www.tools400.de * *=====================================================================* * * * This software is free software, you can redistribute it and/or * * modify it under the terms of the GNU General Public License (GPL) * * as published by the Free Software Foundation. * * * * See GNU General Public License for details. * * http://www.opensource.org * * http://www.opensource.org/licenses/gpl-license.html * * * *=====================================================================* * History: * * * * Datum Name Änderung * * ---------- ------------ --------------------------------------- * * 30.12.2004 Th.Raddatz Changed LSTJOB to use service program * * BASICS1. * * Changed type of handle from POINTER * * to packed decimal. * * * * 17.08.2007 Th.Raddatz Replaced external data structures * * by copy books. * * Added version number (V2.0) to * * copyright information. * * * * 18.12.2008 Th.Raddatz Changed program to /FREE and to work * * BASICS1 V1.10. * * * * 05.04.2016 Th.Raddatz Changed '*' to '*omit'. * * * *=====================================================================* * >>PRE-COMPILER<< * * >>CRTCMD<< CRTRPGMOD MODULE(&LI/&OB) + * * SRCFILE(&SL/&SF) + * * SRCMBR(&SM); * * >>COMPILE<< * * >>PARM<< TRUNCNBR(*NO); * * >>PARM<< DBGVIEW(*LIST); * * >>PARM<< TGTRLS(V6R1M0); * * >>PARM<< OPTION(*EVENTF); * * >>END-COMPILE<< * * >>EXECUTE<< * * >>END-PRE-COMPILER<< * *=====================================================================* H NOMAIN H EXTBININT(*YES) BNDDIR('QC2LE') H DATFMT(*ISO) TIMFMT(*ISO) DEBUG(*YES) /COPY QLSTJOB,COPYRIGHT *=====================================================================* * * Exported procedures /COPY QLSTJOB,PLSTJOB ? * * Imported procedures /COPY QLSTJOB,CLIB ?Prototypes for C-Library /COPY QLSTJOB,CEELIB ?Prototypes for CEE APIs /COPY QLSTJOB,FDQJOB ?Qualified job name /COPY QLSTJOB,GENLSTHDR ?Generic List Header for List APIs /COPY QLSTJOB,QUSLJOB ?List Job (QUSLJOB) API /COPY QLSTJOB,QUSRJOBI ?Retrieve Job Information (QUSRJOBI) API /COPY QBASICS1,PBASICS1 ?Tools/400 Runtime Library * * Type definitions D handle_t DS qualified based(pDummy) D pUsrSpc * D numE 10I 0 D reserved 36A * * Prototypes of internal used procedures D f_getEntry... D PR N opdesc D i_handle value like(lstJob_handle_t) D o_data 32767A options(*varsize) D i_length 10I 0 value * D f_jobSort... D PR N D i_pUsrSpc * value D i_orderBy 10A value D o_msg likeds(msg_t ) * D f_jobSortByName... D PR 10I 0 D i_pKey * value D i_pElement * value * D f_jobSortByName_Desc... D PR 10I 0 D i_pKey * value D i_pElement * value * D f_jobSortByStatus... D PR 10I 0 D i_pKey * value D i_pElement * value * * Global Constants D cLSTJOB_HANDLE_TYPE... D C const('*LSTJOB') * *==================================================================* * Open Job List * ----------------------------------------------------------------- * Using format: JOBL0100 * ----------------------------------------------------------------- * * Return Value: * * cTrue - No error. * cFalse - Error occured. * * Parameter values: * * i_job - Job name, Special values: *, *CURRENT, *ALL. * i_user - User name, Special values: *CURRENT, *ALL. * i_nbr - Job number, Special values: *ALL * i_status - Job status: *ACTIVE, *JOBQ, *OUTQ, *ALL * i_orderBy - Sort sequence: * cLSTJOB_ORDERBY_NONE no sort sequence * cLSTJOB_ORDERBY_NAME sorted by job name (job/user/nbr) * cLSTJOB_ORDERBY_NAME_DESC sorted by job name (job/user/nbr) * cLSTJOB_ORDERBY_STATUS sorted by status * o_handle - List handle for subsequent calls to f_getFirstJob() and * f_getNextJob(). * o_msg - Error message. * *==================================================================* P f_opnJobLst... P B export * D f_opnJobLst... D PI N opdesc D i_job 10A value D i_user 10A value D i_nbr 6A value D i_status 10A value D i_orderBy 10A value D o_handle like(lstJob_handle_t) D o_msg 32767A options(*nopass : D *varsize) * * Return value D o_isDone S N inz(cFalse) * * Parameter positions D p_msg C const(7) * * Fields for optional parameters D msg DS likeds(msg_t ) inz * * Helper fields D isUsrSpc S N inz D pUsrSpc S * inz D qUsrSpc DS likeds(qObj_t ) inz D qJob DS likeds(qJob_t ) inz D errCode DS likeds(errCode_t) inz D strInfMsg DS likeds(strInf_t ) inz * * Handle D handle DS likeds(handle_t ) based(pHandle) *------------------------------------------------------------------- /FREE
o_handle = HANDLE_null();
dou '1';
//?Produce temporary object name qUsrSpc = f_getTmpName(); if (qUsrSpc.name = ''); msg = f_newMsg('CPF9898' : 'Temporary object name + could not be produced.' : cMsg_Escape : 'QCPFMSG' : '*LIBL'); leave; endif;
//?Create user space if (not f_crtUsrSpc(qUsrSpc.name : qUsrSpc.lib : 'List Jobs, JOBL0100, ' + i_orderBy : 65536 : 'TEMP' : '*USE' : msg)); leave; endif;
isUsrSpc = cTrue;
//?List jobs qJob.name = i_job; qJob.user = i_user; qJob.nbr = i_nbr; errCode = f_newApiErrCode(cTrue); QUSLJOB(qUsrSpc: 'JOBL0100': qJob: i_status: errCode);
if (f_isApiError(errCode)); msg = f_cvtApiErrCodeToMsg(errCode); leave; endif;
//?Retrieve user space pointer pUsrSpc = f_rtvUsrSpcPtr(qUsrSpc.name: qUsrSpc.lib: msg); if (msg.ID <> cMSG_ID_OK); leave; endif;
//?Sort job list in user space if (not f_jobSort(pUsrSpc: i_orderBy: msg)); leave; endif;
//?Produce handle o_handle = HANDLE_new(cLSTJOB_HANDLE_TYPE: %size(handle)); pHandle = HANDLE_getPointer(o_handle); handle.pUsrSpc = pUsrSpc; handle.numE = 0; handle.reserved = *ALLx'00';
o_isDone = cTrue; enddo;
if (not o_isDone and isUsrSpc); f_dltUsrSpc(qUsrSpc.name: qUsrSpc.lib); isUsrSpc = cFalse; endif;
//?Return message to caller if (%parms() >= p_msg); CEEGSI(p_msg: strInfMsg.dataType : strInfMsg.curlen : strInfMsg.maxlen: *omit); %subst(o_msg: 1: strInfMsg.curlen) = msg; endif;
return o_isDone;
/END-FREE * P f_opnJobLst... P E * *==================================================================* * Close Job List * ----------------------------------------------------------------- * * Return value: * * cTrue - No error. * cFalse - Error occured. * * Parameter values: * * io_handle - List handle returned by f_opnJobLst(). * *==================================================================* P f_cloJobLst... P B export * D f_cloJobLst... D PI N D io_handle like(lstJob_handle_t) * * Return value D o_isDone S N inz(cFalse) * * Handle D handle DS likeds(handle_t ) based(pHandle) * * Generic List Header for List APIs D genLstHdr DS likeds(genLstHdr_t ) D based(pGenLstHdr) * * Input Section of QUSLJOB API D inpSct DS likeds(QUSLJOB_inpParm_t ) D based(pInpSct) *------------------------------------------------------------------- /FREE
pHandle = HANDLE_getPointer(io_handle);
//?Get user space name pGenLstHdr = handle.pUsrSpc; pInpSct = handle.pUsrSpc + genLstHdr.ofsInpSct;
//?Delete user space o_isDone = f_dltUsrSpc(inpSct.qUsrSpc.name: inpSct.qUsrSpc.lib);
//?Delete handle HANDLE_delete(io_handle);
return o_isDone;
/END-FREE * P f_cloJobLst... P E * *==================================================================* * Get First Job * ----------------------------------------------------------------- * * Return value: * * cTrue - No error. * cFalse - Error occured. * * Parameter values: * * i_handle - List handle returned by f_opnJobLst(). * o_data - list entry data of type JOBL0100. * *==================================================================* P f_getFirstJob... P B export * D f_getFirstJob... D PI N opdesc D i_handle value like(lstJob_handle_t) D o_data 32767A options(*varsize) * * Return value D o_isDone S N inz(cFalse) * * Parameter positions D p_data C const(2) * * Handle D handle DS likeds(handle_t ) based(pHandle) * * Helper fields D strInfData DS likeds(strInf_t ) inz *------------------------------------------------------------------- /FREE
pHandle = HANDLE_getPointer(i_handle);
//?Get length of o_data CEEGSI(p_data: strInfData.datatype : strInfData.curlen : strInfData.maxlen : *omit);
//?Get first entry handle.numE = 0;
//?Retrieve entry data o_isDone = f_getEntry(i_handle: o_data: strInfData.curlen);
return o_isDone;
/END-FREE * P f_getFirstJob... P E * *==================================================================* * Get Next Job * ----------------------------------------------------------------- * * Return value: * * cTrue - No error. * cFalse - Error occured. * * Parameter values: * * i_handle - List handle returned by f_opnJobLst(). * o_data - list entry data of type JOBL0100. * *==================================================================* P f_getNextJob... P B export * D f_getNextJob... D PI N opdesc D i_handle value like(lstJob_handle_t) D o_data 32767A options(*varsize) * * Return value D o_isDone S N inz(cFalse) * * Parameter positions D p_data C const(2) * * Helper fields D strInfData DS likeds(strInf_t ) inz *------------------------------------------------------------------- /FREE
//?Get length of o_data CEEGSI(p_data: strInfData.datatype : strInfData.curlen : strInfData.maxlen : *omit);
//?Retrieve entry data o_isDone = f_getEntry(i_handle: o_data: strInfData.curlen);
return o_isDone;
/END-FREE * P f_getNextJob... P E * *==================================================================* * Get Number of Jobs available * ----------------------------------------------------------------- * * Return value: * * numEntries - Number of entries in the list. * * Parameter values: * * i_handle - List handle returned by f_opnJobLst(). * *==================================================================* P f_getNumJobAvl... P B export * D f_getNumJobAvl... D PI 10I 0 D i_handle value like(lstJob_handle_t) * * Return value D numJobAvl S 10I 0 inz * * Handle D handle DS likeds(handle_t ) based(pHandle) * * Generic List Header for List APIs D genLstHdr DS likeds(genLstHdr_t ) D based(handle.pUsrSpc) *------------------------------------------------------------------- /FREE
pHandle = HANDLE_getPointer(i_handle);
return genLstHdr.numE;
/END-FREE * P f_getNumJobAvl... P E * *==================================================================* * Retrieve Job Attributes * ----------------------------------------------------------------- * * Return value: * * rtnValue - The job attributes retrieved from the job. * * Parameter values: * * i_intJobID - Internal job ID returned by f_getFirstJob() or * f_getNextJob(). * i_format - The format of the job list to be returned. * o_msg - Error message. * *==================================================================* P f_rtvJobA... P B export * D f_rtvJobA... D PI 8191A opdesc varying D i_intJobID 16A const D i_format 8A const D o_msg 32767A options(*nopass: *varsize) * * Return value D rtnValue S 8192A inz * * Parameter positions D p_msg C const(3) * * Fields for optional parameters D msg DS likeds(msg_t ) inz * * Local fields D errCode DS likeds(errCode_t ) inz * * Helper fields D strInfMsg DS likeds(strInf_t ) inz *------------------------------------------------------------------- /FREE
//?If o_msg was passed, ... if (%parms() >= p_msg); //?... then initialize API error code to return error information errCode = f_newApiErrCode(cTrue); else; //?... else initialize API error code to send an ESCAPE message errCode = f_newApiErrCode(cFalse); endif;
//?Retrieve job attributes Clear rtnValue; QUSRJOBI(rtnvalue: %size(rtnValue): i_format : '*INT': i_intJobID: errCode);
//?Convert API error code information to message msg = f_cvtApiErrCodeToMsg(errCode);
//?If o_msg was passed, ... if (%parms() >= p_msg); //?... then pass back error information CEEGSI(p_msg: strInfMsg.datatype : strInfMsg.curlen : strInfMsg.maxlen : *omit); %subst(o_msg: 1: strInfMsg.curlen) = msg; endif;
return %trimR(rtnValue);
/END-FREE * P f_rtvJobA... P E * *==================================================================* * Get Entry *==================================================================* P f_getEntry... P B * D f_getEntry... D PI N opdesc D i_handle value like(lstJob_handle_t) D o_data 32767A options(*varsize) D i_length 10I 0 value * * Return value D o_isDone S N inz(cFalse) * * Handle D handle DS likeds(handle_t ) based(pHandle) * * Local fields D pDest S * inz D pSrc S * inz D count S 10I 0 inz * * Generic List Header for List APIs D genLstHdr DS likeds(genLstHdr_t ) D based(handle.pUsrSpc) *------------------------------------------------------------------- /FREE
pHandle = HANDLE_getPointer(i_handle);
//?Return to caller if there are no entries left if (handle.numE >= genLstHdr.numE); o_isDone = cFalse; return o_isDone; endif;
//?Copy entry to o_data pDest = %addr(o_data); pSrc = handle.pUsrSpc + genLstHdr.ofsLstSct + (handle.numE * genLstHdr.sizeE);
if (i_length < genLstHdr.sizeE); count = i_length; else; count = genLstHdr.sizeE; endif;
memCpy(pDest: pSrc: count);
//?Increase number of entries returned handle.numE = handle.numE + 1;
//?Return return value o_isDone = cTrue;
return o_isDone;
/END-FREE * P f_getEntry... P E * *==================================================================* * Sort User Space *==================================================================* P f_jobSort... P B * D f_jobSort... D PI N D i_pUsrSpc * value D i_orderBy 10A value D o_msg likeds(msg_t ) * * Return value D o_isDone S N inz(cFalse) * * Helper fields D pCompFunc S * inz procptr * * Generic List Header for List APIs D genLstHdr DS likeds(genLstHdr_t ) D based(i_pUsrSpc) *------------------------------------------------------------------- /FREE
//?Get address of sort procedure ... select;
//?... do not sort when (i_orderBy = cLSTJOB_ORDERBY_NONE); pCompFunc = *NULL; o_isDone = cTrue; o_msg = f_newMsg(cMSG_ID_OK);
//?... sort by name when (i_orderBy = cLSTJOB_ORDERBY_NAME); pCompFunc = %paddr('F_JOBSORTBYNAME'); o_isDone = cTrue; o_msg = f_newMsg(cMSG_ID_OK);
//?... sort by name (descending) when (i_orderBy = cLSTJOB_ORDERBY_NAME_DESC); pCompFunc = %paddr('F_JOBSORTBYNAME_DESC'); o_isDone = cTrue; o_msg = f_newMsg(cMSG_ID_OK);
//?... sort by status when (i_orderBy = cLSTJOB_ORDERBY_STATUS); pCompFunc = %paddr('F_JOBSORTBYSTATUS'); o_isDone = cTrue; o_msg = f_newMsg(cMSG_ID_OK);
//?... ... unsupported sort value other; pCompFunc = *NULL; o_isDone = cFalse; o_msg = f_newMsg('CPF9898' : 'Value ' + %trim(i_orderBy) + ' for parameter ''orderBy'' + not supported' : cMsg_Escape : 'QCPFMSG' : '*LIBL'); endsl;
