return o_isDone;
/END-FREE * P f_jobSort... P E * *==================================================================* * Job List: Sort By Name *==================================================================* P f_jobSortByName... P B * D f_jobSortByName... D PI 10I 0 D i_pKey * value D i_pElement * value * * Define key D key DS based(i_pKey) likeds(jobl0100_t ) * D keyValue DS qualified D job like(key.job ) D user like(key.user ) D nbr like(key.nbr ) * * Define element D element DS based(i_pElement) likeds(jobl0100_t ) * D elementValue DS qualified D job like(element.job ) D user like(element.user ) D nbr like(element.nbr ) * * Return value D o_result S 10I 0 inz *------------------------------------------------------------------- /FREE
keyValue.job = key.job; keyValue.user = key.user; keyValue.nbr = key.nbr;
elementValue.job = element.job; elementValue.user = element.user; elementValue.nbr = element.nbr;
select; when (keyValue < elementValue); o_result = -1; when (keyValue > elementValue); o_result = 1; other; o_result = 0; endsl;
return o_result;
